// src/pages/Login.js  (or wherever your file is)
import React, { useState } from "react";
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  Paper,
  Alert,
  CircularProgress,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import api from "../api"; // <- centralized axios

export default function Login() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ mobile: "" });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
    if (error) setError("");
  };

  const validateMobile = (mobile) => /^[6-9]\d{9}$/.test(mobile);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateMobile(formData.mobile)) {
      setError("Enter a valid 10-digit mobile number starting with 6-9.");
      return;
    }

    try {
      setLoading(true);
      const res = await api.post("/login", { mobile: formData.mobile });
      // res.data expected shape: { success: true, ... }
      if (res.data?.success) {
        navigate("/dashboard");
      } else {
        setError(res.data?.message || "Login failed. Try again.");
      }
    } catch (err) {
      console.error("Login error normalized:", err);
      setError(err.message || "Server error. Please try again later.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={3} sx={{ p: 4, mt: 5, borderRadius: 3 }}>
        <Typography variant="h4" align="center" gutterBottom sx={{ color: "orangered", fontWeight: "bold" }}>
          Rider App
        </Typography>
        <Typography variant="body1" align="center" sx={{ mb: 3 }}>
          Welcome back! Please login
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

        <Box component="form" onSubmit={handleSubmit}>
          <TextField
            fullWidth
            type="tel"
            label="Mobile Number"
            name="mobile"
            value={formData.mobile}
            onChange={handleChange}
            margin="normal"
            inputProps={{ maxLength: 10 }}
            required
            autoFocus
          />

          <Button type="submit" fullWidth variant="contained"
            sx={{ mt: 2, bgcolor: "orangered", "&:hover": { bgcolor: "darkred" } }}
            disabled={loading}
          >
            {loading ? <CircularProgress size={24} sx={{ color: "white" }} /> : "Login"}
          </Button>
        </Box>

        <Typography align="center" sx={{ mt: 2 }}>
          Don’t have an account?{" "}
          <Button variant="text" onClick={() => navigate("/signup")} sx={{ color: "orangered" }}>
            Sign Up
          </Button>
        </Typography>
      </Paper>
    </Container>
  );
}
